const cp = require('child_process');
const url = ($json.body && $json.body.url) || '';
if (!url) return [{ json: { output: '❌ Falta el parámetro url' } }];

try {
  // Escape docker container to host GUI using nsenter via mounted docker socket
  const cmd = `docker run --rm --pid=host --privileged alpine nsenter -t 1 -m -u -n -i su - lucy-ubuntu -c "export DISPLAY=:0; nohup xdg-open '${url}' > /dev/null 2>&1 &"`;
  cp.exec(cmd, (error, stdout, stderr) => {
    if (error) {
      console.error(`exec error: ${error}`);
      // In an async context, the response is already sent, so logging is the primary way to handle this.
    }
  });
  return [{ json: { output: '▶️ Abriendo video en el host: ' + url } }];
} catch(e) {
  return [{ json: { output: '❌ Error al abrir video: ' + e.message } }];
}
